const EQUIP_SLOTS={plg1:[0,1,2,3],plg2Top:[11],plg2Bottom:[8,9,10],plg3:[4,5,6,7]};class PledgeLayout{constructor(s){this.el=$(`#${s.targetId}`),this.oathSetInfo=s.oathSetInfo??{},this.crystals=s.crystals??[],this.render()}render(){const s=s=>this.crystals.length>0&&this.crystals[s]?`<div class="eq-slot b-${this.crystals[s].itemRarity}" data-t="${s}" title="${this.crystals[s].itemName??""}">\n                    <img width="32px" height="32px" onerror="this.src ='./static/images/cancel.png'" src="https://img-api.neople.co.kr/df/items/${this.crystals[s].itemId}">\n                </div>`:`<div class="eq-slot eq-empty" data-t="${s}" title=""></div>`,i=`\n            <div class="equip-layout">\n                <div class="plg1">\n                    ${EQUIP_SLOTS.plg1.map(s).join("\n                    ")}\n                </div>\n                <div class="plg2">\n                    <div class="plg2-top">\n                        ${EQUIP_SLOTS.plg2Top.map(s).join("")}\n                    </div>\n                    <div class="plg2-bottom">\n                        ${EQUIP_SLOTS.plg2Bottom.map(s).join("\n                        ")}\n                    </div>\n                </div>\n                <div class="plg3">\n                    ${EQUIP_SLOTS.plg3.map(s).join("\n                    ")}\n                </div>\n            </div>`;this.el.html(i)}}class ReinCard{constructor(s,i){this.id=s.id,this.el=$(`#${this.id}`),this.itemId=s.itemId,this.itemNm=s.itemNm,this.summary=s.summary,this.list=s.list,this.i=s.i,this.render()}render(){const s=this.summary.map(s=>`\n            <div class="r-card-list">\n                <div class="col-4">${s.a}</div>\n                <div class="col-4">${s.s} 성공</div>\n                <div class="col-4">${s.f} 실패</div>\n            </div>\n        `).join(""),i=this.list.map(s=>`\n            <li>\n                <div class="w55">${s.date}</div>\n                <div class="w20 ta-center">${s.before} > ${s.after}</div>\n                <div class="w25 ta-center ${s.result?'color-success"> 성공':'color-fail">실패'}</div>\n                ${s.ticket?`<div class="w100">* ${s.ticket}</div>`:""}\n            </li>\n        `).join(""),t=`\n          <div class="card mb-2">\n            <div class="card-header">\n                <img class="setImg" src="https://img-api.neople.co.kr/df/items/${this.itemId}" />\n                ${this.itemNm}\n            </div>\n            ${s}\n            <div id="ls_${this.id}_${this.i}" class="card-header fold-reinforce">상세 이력</div>\n            ${this.list.length>0?`<ul id="ul_${this.id}_${this.i}" class="list-group">`:""}\n              ${i}\n            ${this.list.length>0?"</ul>":""}\n          </div>`;this.el.append(t),$(`#ls_${this.id}_${this.i}`).click(s=>{$(s.target).hasClass("open")?($(s.target).removeClass("open"),$(`#ul_${this.id}_${this.i}`).removeClass("show")):($(s.target).addClass("open"),$(`#ul_${this.id}_${this.i}`).addClass("show"))})}}